package com.example.documentviewer;

import android.content.Intent;
import android.net.Uri;
import android.os.Bundle;
import android.widget.ImageView;
import androidx.appcompat.app.AppCompatActivity;
import com.github.barteksc.pdfviewer.PDFView;
import java.io.File;

public class DocumentViewerActivity extends AppCompatActivity {

    private PDFView pdfView;
    private ImageView imageView;

    @Override
    protected void onCreate(Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);
        setContentView(R.layout.activity_document_viewer);

        pdfView = findViewById(R.id.pdfView);
        imageView = findViewById(R.id.imageView);

        Intent intent = getIntent();
        if (Intent.ACTION_VIEW.equals(intent.getAction())) {
            Uri fileUri = intent.getData();
            if (fileUri != null) {
                String scheme = fileUri.getScheme();
                if ("content".equals(scheme)) {
                    handleContentUri(fileUri);
                } else if ("file".equals(scheme)) {
                    handleFileUri(fileUri);
                }
            }
        }
    }

    private void handleContentUri(Uri uri) {
        // Handle content URI for PDF and image files
        String mimeType = getContentResolver().getType(uri);
        if (mimeType != null && (mimeType.startsWith("image") || mimeType.equals("application/pdf"))) {
            try {
                InputStream inputStream = getContentResolver().openInputStream(uri);
                if (mimeType.startsWith("image")) {
                    imageView.setImageBitmap(BitmapFactory.decodeStream(inputStream));
                } else if (mimeType.equals("application/pdf")) {
                    pdfView.fromUri(uri).load();
                }
            } catch (IOException e) {
                e.printStackTrace();
            }
        }
    }

    private void handleFileUri(Uri uri) {
        // Handle file URI for PDF and image files
        String path = uri.getPath();
        File file = new File(path);
        if (file.exists()) {
            String mimeType = getContentResolver().getType(uri);
            if (mimeType != null && (mimeType.startsWith("image") || mimeType.equals("application/pdf"))) {
                try {
                    InputStream inputStream = getContentResolver().openInputStream(uri);
                    if (mimeType.startsWith("image")) {
                        imageView.setImageBitmap(BitmapFactory.decodeStream(inputStream));
                    } else if (mimeType.equals("application/pdf")) {
                        pdfView.fromUri(uri).load();
                    }
                } catch (IOException e) {
                    e.printStackTrace();
                }
            }
        }
    }

    @Override
    protected void onNewIntent(Intent intent) {
        super.onNewIntent(intent);
        setIntent(intent);
        handleIntent(intent);
    }

    private void handleIntent(Intent intent) {
        if (Intent.ACTION_VIEW.equals(intent.getAction())) {
            Uri fileUri = intent.getData();
            if (fileUri != null) {
                String scheme = fileUri.getScheme();
                if ("content".equals(scheme)) {
                    handleContentUri(fileUri);
                } else if ("file".equals(scheme)) {
                    handleFileUri(fileUri);
                }
            }
        }
    }

    @Override
    public void onRequestPermissionsResult(int requestCode, @NonNull String[] permissions, @NonNull int[] grantResults) {
        super.onRequestPermissionsResult(requestCode, permissions, grantResults);
        // Handle permission results if needed
    }
}